import 'package:flutter/material.dart';
import 'package:webview_flutter/webview_flutter.dart';

void main() {
  runApp(MyApp());
}

class MyApp extends StatelessWidget {
  @override
  Widget build(BuildContext context) {
    return MaterialApp(
      title: 'Flutter WebView Example',
      theme: ThemeData(
        primarySwatch: Colors.blue,
      ),
      home: Scaffold(
        appBar: AppBar(
          title: Text('Flutter WebView Example'),
        ),
        body: WebviewScaffold(
          url: 'YOUR_MOBILE_WEBSITE_URL',
          javascriptMode: JavascriptMode.unrestricted,
          initialChild: Container(),
          navigationDelegate: (NavigationRequest request) {
            if (request.url.host == 'YOUR_MOBILE_WEBSITE_DOMAIN') {
              return NavigationDecision.navigate;
            }
            return NavigationDecision.prevent;
          },
          onWebViewCreated: (WebViewController webViewController) {
            // Enable JavaScript and set up a JavaScript channel to call Dart functions
            webViewController.evaluateJavascript(
              'window.flutter_inappwebview = window.flutter_inappwebview || {};',
            );
            webViewController.postMessage(
                'JavaScriptChannelCreated'); // Notify the web page that the JavaScript channel is ready
          },
        ),
      ),
    );
  }
}